'SELECT TO_CHAR(TRUNC(CAST(c.fecha_hora AS DATE), ''MM''), ''YYYY-MM'') AS mes,
       e.codigo AS estado,
       COUNT(*) AS total_citas
FROM cita c
JOIN estado_cita e ON e.id_estado = c.id_estado
GROUP BY ROLLUP (TRUNC(CAST(c.fecha_hora AS DATE), ''MM''), e.codigo)
ORDER BY mes, estado');

