'WITH base AS (
  SELECT TO_CHAR(TRUNC(CAST(c.fecha_hora AS DATE), ''MM''), ''YYYY-MM'') AS mes,
         e.codigo AS estado
  FROM cita c
  JOIN estado_cita e ON e.id_estado = c.id_estado
)
SELECT *
FROM base
PIVOT (
  COUNT(*) FOR estado IN (
    ''PROGRAMADA'' AS programada,
    ''ATENDIDA'' AS atendida,
    ''CANCELADA'' AS cancelada
  )
)
ORDER BY mes');

